import { Component, OnInit, ViewChild } from '@angular/core';
import { IonCheckbox, IonSegment } from '@ionic/angular';
import { AlertService } from 'src/app/core/services/alert.service';
import { MohassilAuthService } from 'src/app/core/services/AuthenticationServices/mohassil-auth.service';
import { pagingService } from 'src/app/core/services/paging.service';
import { TransactionService } from 'src/app/core/services/transaction.service';
import { PostingTransactions } from 'src/app/views/Models/Transaction/PostingTransactions';

interface CheckPageTypes {
  isPostingTransaction: boolean;
  isPostingCancelTransaction: boolean;
  isPostingPenalty: boolean;
  isPostingCancelPenalty: boolean;
}

@Component({
  selector: 'app-post-transactions',
  templateUrl: './post-transactions.page.html',
  styleUrls: ['./post-transactions.page.css'],
})

export class PostTransactionsPage implements OnInit {
  @ViewChild("ionCheckBox") ionCheckBox: IonCheckbox;
  @ViewChild("ionSegment") ionSegment: IonSegment;

  //region Variables
  showLoader: boolean = false;
  pageTypeAccessRights: any[];
  checkPageTypes: CheckPageTypes = {
    isPostingTransaction: false,
    isPostingCancelTransaction: false,
    isPostingPenalty: false,
    isPostingCancelPenalty: false
  };
  windowCodesToCheck: any[] = ["5627", "5628", "5629", "5630"];
  PostingTransactionPageType: any[] = [
    {
      pageTypeDesc: "تنفيذ حركات السداد",
      pageCode: 5627,
      pageAction: 1,
    },
    {
      pageTypeDesc: "تنفيذ حركات الغرامة",
      pageCode: 5628,
      pageAction: 2,
    },
    {
      pageTypeDesc: "تنفيذ حركات الغاء السداد",
      pageCode: 5629,
      pageAction: 3,
    },
    {
      pageTypeDesc: "تنفيذ حركات الغاء الغرامة",
      pageCode: 5630,
      pageAction: 4,
    },
  ];
  pageType: any;
  postingTransactions : Array<PostingTransactions & { isChecked: boolean }>;
  TransactionPage: number = 1;
  selectedTransactions: PostingTransactions[];
  segmentSelected: boolean = false;
  //endregion

  constructor(    
    private authService: MohassilAuthService,
    public pagingService: pagingService,
    private transactionService: TransactionService,
    private alertService: AlertService
  ) { }

  async ngOnInit() {
    this.pageTypeAccessRights = await this.authService.getAccessRights();
    // Filter the clientTransactionPageType array according to access rights
    const filteredClientTransactionPageTypes =
      this.PostingTransactionPageType.filter((page) => {
        return this.windowCodesToCheck.some(
          (x) => x === page.pageCode.toString() && this.checkWindowCodeExists(x)
        );
      });
    this.PostingTransactionPageType = filteredClientTransactionPageTypes;

    await this.getTransactions(this.PostingTransactionPageType[0].pageCode.toString(), this.PostingTransactionPageType[0].pageAction);
    this.ionSegment.value = this.PostingTransactionPageType[0].pageCode.toString();
  }

  //region Ion Segment
  async changePageType(event) {
    if(event.detail.value.toString() === "0") return;
    this.pageType = this.PostingTransactionPageType.find(
      (x) => x.pageCode.toString() === event.detail.value.toString()
    );
    this.checkPageTypes.isPostingTransaction =
      this.checkWindowCodeExists("5627");
    this.checkPageTypes.isPostingCancelTransaction =
      this.checkWindowCodeExists("5630");
    this.checkPageTypes.isPostingPenalty =
      this.checkWindowCodeExists("5628");
    this.checkPageTypes.isPostingCancelPenalty =
      this.checkWindowCodeExists("5629");

    await this.getTransactions(this.pageType.pageCode.toString(), this.pageType.pageAction);
  }
  checkWindowCodeExists = (WindowCode: string): boolean => {
    return this.pageTypeAccessRights.some((x) => x.window_code === WindowCode);
  };
  async getTransactions(pageCode: string, pageAction: number) {
    switch (pageCode) {
      case "5627": {
        this.checkPageTypes.isPostingTransaction = true;
        this.checkPageTypes.isPostingPenalty = false;
        this.checkPageTypes.isPostingCancelTransaction = false;
        this.checkPageTypes.isPostingCancelPenalty = false;
        break;
      }
      case "5628": {
        this.checkPageTypes.isPostingTransaction = false;
        this.checkPageTypes.isPostingPenalty = true;
        this.checkPageTypes.isPostingCancelTransaction = false;
        this.checkPageTypes.isPostingCancelPenalty = false;
        break;
      }
      case "5629": {
        this.checkPageTypes.isPostingTransaction = false;
        this.checkPageTypes.isPostingPenalty = false;
        this.checkPageTypes.isPostingCancelTransaction = true;
        this.checkPageTypes.isPostingCancelPenalty = false;
        break;
      }
      case "5630": {
        this.checkPageTypes.isPostingTransaction = false;
        this.checkPageTypes.isPostingPenalty = false;
        this.checkPageTypes.isPostingCancelTransaction = false;
        this.checkPageTypes.isPostingCancelPenalty = true;
        break;
      }
    }
    this.TransactionPage = 1;
    this.selectedTransactions = [];
    this.showLoader = true;
    this.postingTransactions = [];
    this.postingTransactions = (await this.transactionService.GetPostingTransactions(pageAction).toPromise()).map((x)=> ({
      ...x,
      isChecked: false,
    }));
    this.segmentSelected = true;
    this.showLoader = false;
  }
  //endregion

  
  //region Checbox
  set isAllSelected(value: boolean) {
    this.postingTransactions.forEach((trans) => (trans.isChecked = value));
  }
  onCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.postingTransactions.forEach((trans) => (trans.isChecked = isChecked));
    this.updateSelectedLoanForAll(isChecked);
  }
  updateSelectedLoanForAll(isChecked: boolean) {
    this.selectedTransactions = [];
    if (isChecked) {
      this.postingTransactions.forEach((trans) => {
        this.selectedTransactions.push(trans);
      });
    }
  }
  onCheckboxChange(event: any, trans: any, index: any) {
    const selectedApp =
      this.postingTransactions[
        index + this.pagingService.pageSize * (this.TransactionPage - 1)
      ];

      selectedApp.isChecked = event.target.checked;
    this.updateSelectedApplicaiton(trans, event.target.checked);
    this.updateMasterCheckbox();
    if (this.postingTransactions.length !== this.selectedTransactions.length) {
      if(this.selectedTransactions.length === 0) {
        this.ionCheckBox.indeterminate = false;
      } else {
        this.ionCheckBox.indeterminate = true;
      }
    } else if (this.postingTransactions.length === this.selectedTransactions.length) {
      this.ionCheckBox.indeterminate = false;
      this.ionCheckBox.checked = true;
      this.isAllSelected = true;
    }
  }
  updateSelectedApplicaiton(trans: any, isChecked: boolean) {
    const index = this.selectedTransactions.indexOf(trans);
    if (isChecked && index === -1) {
      this.selectedTransactions.push(trans);
    } else if (!isChecked && index > -1) {
      this.selectedTransactions.splice(index, 1);
    }
  }
  updateMasterCheckbox() {
    const allSelected = this.postingTransactions.every(
      (app) => app.isChecked
    );
    const someSelected = this.postingTransactions.some(
      (app) => app.isChecked
    );

    if (allSelected) {
      this.isAllSelected = true;
    } else if (!someSelected) {
      this.ionCheckBox.checked = false;
      this.ionCheckBox.indeterminate = false;
      this.isAllSelected = false;
    }
  }
  changePaginationPage = (newPage: number): void => {
    this.TransactionPage = newPage;
  };
  //endregion

  //region Submit & Back
  async postTransactions(){
    if (await this.alertService.SaveAlert("هل انت متاكد من التنفيذ؟"))
    {
      console.log("this.selectedTransactions:" , this.selectedTransactions)
      this.showLoader = true;
      this.transactionService.postTransactions(this.selectedTransactions).subscribe({
        next: async () => {
          this.showLoader = false;
          await this.alertService.showAlertConfirm("تم الحفظ بنجاح", false);
          this.TransactionPage = 1;
          this.selectedTransactions = [];
          this.showLoader = true;
          this.postingTransactions = [];
          this.postingTransactions = (await this.transactionService.GetPostingTransactions(this.pageType.pageAction).toPromise()).map((x)=> ({
            ...x,
            isChecked: false,
          }));
          this.segmentSelected = true;
          this.showLoader = false;
        },
        error: async (err) => {
            await this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
        },
      })
    }
  }
  backbtn() {
    this.segmentSelected = false;
    this.isAllSelected = false;
    this.postingTransactions = [];
    this.selectedTransactions = [];
    this.TransactionPage = 1;
    this.ionSegment.value = "0";
  }
  //endregion
}
